using Apex.Application.Abstractions.Exceptions;using Apex.Modules.Accounting.ChartOfAccounts.Domain;using Apex.Modules.Accounting.ChartOfAccounts.Repositories;using Microsoft.AspNetCore.Mvc;
namespace Apex.Modules.Accounting.ChartOfAccounts.UseCases.GetAccount;
internal sealed record GetAccountResponse(long Id,string Level,long? ParentId,string Code,string Name,string? Nature,string? DetailAccountType,string Status,DateTime CreatedAt,DateTime? UpdatedAt,DateTime? ArchivedAt);
internal sealed class GetAccountHandler(IAccountClassReadRepository classes,IGeneralAccountReadRepository generals,ISubsidiaryAccountReadRepository subsidiaries){public async Task<GetAccountResponse> HandleAsync(AccountLevel level,long id,CancellationToken ct)=>level switch{AccountLevel.AccountClass=>Map(await classes.GetAsync(id,ct)??throw new NotFoundException("Account class was not found.",ChartOfAccountsErrors.AccountClassNotFound)),AccountLevel.GeneralAccount=>Map(await generals.GetAsync(id,ct)??throw new NotFoundException("General account was not found.",ChartOfAccountsErrors.GeneralAccountNotFound)),AccountLevel.SubsidiaryAccount=>Map(await subsidiaries.GetAsync(id,ct)??throw new NotFoundException("Subsidiary account was not found.",ChartOfAccountsErrors.SubsidiaryAccountNotFound)),_=>throw new BusinessRuleException("Unknown account level.","invalid_account_level")};private static GetAccountResponse Map(Repositories.Rows.AccountClassRow r)=>new(r.Id,"ACCOUNT_CLASS",null,r.Code,r.Name,null,null,r.Status,r.CreatedAt,r.UpdatedAt,r.ArchivedAt);private static GetAccountResponse Map(Repositories.Rows.GeneralAccountRow r)=>new(r.Id,"GENERAL_ACCOUNT",r.AccountClassId,r.Code,r.Name,r.Nature,null,r.Status,r.CreatedAt,r.UpdatedAt,r.ArchivedAt);private static GetAccountResponse Map(Repositories.Rows.SubsidiaryAccountRow r)=>new(r.Id,"SUBSIDIARY_ACCOUNT",r.GeneralAccountId,r.Code,r.Name,r.Nature,r.DetailAccountType,r.Status,r.CreatedAt,r.UpdatedAt,r.ArchivedAt);}
internal static class GetAccountEndpoint{internal static RouteGroupBuilder MapGetAccountEndpoint(this RouteGroupBuilder g){g.MapGet("/{level}/{id:long}",async(AccountLevel level,long id,[FromServices]GetAccountHandler h,CancellationToken ct)=>Results.Ok(await h.HandleAsync(level,id,ct))).WithName("GetChartAccount");return g;}}
